"""
TDD Stage: full_normalize
Full normalization without affine: subtract mean, square, compute variance, add eps, rsqrt, multiply to normalize.
"""

import pytest
import torch
import ttnn

from .layer_norm import layer_norm


def pytorch_reference(input_tensor):
    """PyTorch reference for this stage."""
    x = input_tensor.float()
    return (x - x.mean(dim=-1, keepdim=True)) / torch.sqrt(x.var(dim=-1, keepdim=True, correction=0) + 1e-5)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((32, 32), id="32x32"),
        pytest.param((64, 128), id="64x128"),
        pytest.param((32, 256), id="32x256"),
        pytest.param((128, 64), id="128x64"),
    ],
)
def test_full_normalize(device, shape):
    """Verify Full normalization without affine: subtract mean, square, compute variance, add eps, rsqrt, multiply to normalize.."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
